def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_distance = np.inf

    for node in unvisited_nodes:
        dist_to_unvisited_nodes = np.sum(distance_matrix[node, unvisited_nodes])
        dist_to_destination = distance_matrix[node, destination_node]
        total_distance = dist_to_unvisited_nodes + dist_to_destination

        if total_distance < min_distance:
            min_distance = total_distance
            next_node = node
        elif total_distance == min_distance:
            if np.random.random() > 0.5:
                next_node = node

    return next_node

import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    max_product = -np.inf
    next_node = None

    for node in unvisited_nodes:
        if node == current_node:
            continue

        # Calculate the product of distances
        product = distance_matrix[current_node, node] * distance_matrix[node, destination_node] / distance_matrix[current_node, destination_node]

        if product > max_product:
            max_product = product
            next_node = node

    return next_node
